INSERT INTO mtkin.cartas (id, nome_carta, tipo_carta, caminho_imagem, categoria, equipar_onde, n_pode_equipar, forca, item, nivel, fulga_minima, texto_da_carta, permite_mochila, qtd_max, valor, uso_em_combate) VALUES
(1, 'Tô de folga', 'Cidade', 'Cartas/Cidade/1.png', 'Chacaras', '80', NULL, 1, 0, 0, 0, 'Poucos momentos para relaxar, mas quando dá essa rede e piscina são a fonte de renovação, força +1.', FALSE, 1, 0, FALSE),
(2, 'Gancho', 'Cidade', 'Cartas/Cidade/10.jpg', 'Isca', NULL, NULL, 0, 0, 0, 0, 'Consegue roubar a carta de item de um jogador, escolha uma carta na mochila ou cartela dele, use em qualquer combate.', TRUE, 2, 0, FALSE),
(3, 'Pó espanta zumbi', 'Cidade', 'Cartas/Cidade/11.jpg', 'Isca', NULL, NULL, 0, 0, 0, 0, 'Pó que ao jogar afasta zumbi devido a confundir o cheiro de humanos, use para trocar o zumbi por outro da sua mão para combater.', TRUE, 2, 0, FALSE),
(4, 'Fraco', 'Cidade', 'Cartas/Cidade/12.jpg', 'Isca', NULL, NULL, 0, 0, 0, 0, 'Espirre em um zumbi q ele vai perder a força, -4 de força para o zumbi, pegue 1 item a menos.', TRUE, 2, 0, FALSE),
(5, 'Modificador', 'Cidade', 'Cartas/Cidade/13.jpg', 'Isca', '86', NULL, 0, 0, 0, 0, 'Pode modificar um item fazendo ele ficar mais forte, coloque junto de um item da carteira e este item vai te dar +3 de força.', TRUE, 2, 0, FALSE),
(6, 'Dentro do esgoto', 'Cidade', 'Cartas/Cidade/14.jpg', 'Isca', NULL, NULL, 0, 0, 0, 0, 'Passe pelo esgoto para subir um nível, cartas de chácara com 0 força sobre um nível junto.', TRUE, 1, 0, FALSE),
(7, 'Sangue contaminado', 'Cidade', 'Cartas/Cidade/15.jpg', 'Isca', NULL, NULL, 0, 0, 0, 0, 'Jogue esta carta em um zumbi para duplicar a força dele, os itens também duplicam.', TRUE, 2, 0, FALSE),
(8, 'Mochila rasgada', 'Cidade', 'Cartas/Cidade/16.jpg', 'Armadilha', NULL, NULL, 0, 0, 0, 0, 'Sua mochila possui um rasgo, perca um item sem peso.', TRUE, 2, 0, FALSE),
(9, 'Armadilha de urso', 'Cidade', 'Cartas/Cidade/17.jpg', 'Armadilha', NULL, NULL, 0, 0, 0, 0, 'Você prendeu o pé nessa armadilha, perca uma carta de pé.', FALSE, 2, 0, FALSE),
(10, 'Contrato secreto', 'Cidade', 'Cartas/Cidade/18.jpg', 'Armadilha', NULL, NULL, 0, 0, 0, 0, 'Entregue ao espião uma carta de valor, ele vai roubar as cartas dos jogadores que somadas deem o valor da sua carta, se o jogador não tiver este valor ele perde um nível.', TRUE, 1, 0, FALSE),
(11, 'Paranoia de identidade', 'Cidade', 'Cartas/Cidade/19.jpg', 'Armadilha', NULL, NULL, 0, 0, 0, 0, 'Descarte o personagem q estiver usando e troque pelo primeiro que encontrar no descarte, se não tiver um personagem apenas descarte o seu.', TRUE, 1, 0, FALSE),
(12, 'Nazaré', 'Cidade', 'Cartas/Cidade/2.png', 'Chacaras', '80', NULL, 1, 0, 0, 0, 'Lugar de oração e um abrigo com uma vista estratégica, força +1.', FALSE, 1, 0, FALSE),
(13, 'Combinado', 'Cidade', 'Cartas/Cidade/20.jpg', 'Armadilha', NULL, NULL, 0, 0, 0, 0, 'Um jogador da direita e um da esquerda de quem recebeu esta carta combinam de roubar uma carta da mochila da vitima.', TRUE, 1, 0, FALSE),
(14, 'MOCHILA RASGADA', 'Cidade', 'Cartas/Cidade/21.jpg', 'Armadilha', NULL, NULL, 0, 0, 0, 0, 'Perca um item pesado.', TRUE, 2, 0, FALSE),
(15, 'Colete falsificado', 'Cidade', 'Cartas/Cidade/22.jpg', 'Armadilha', NULL, NULL, 0, 0, 0, 0, 'Perca um item de corpo.', TRUE, 2, 0, FALSE),
(16, 'Traindo escondido', 'Cidade', 'Cartas/Cidade/23.jpg', 'Armadilha', NULL, NULL, 0, 0, 0, 0, 'O jogador que te deu esta carta estava escondido e empurrou vc para trás, perca 1 nível.', TRUE, 2, 0, FALSE),
(17, 'Mão na mochila', 'Cidade', 'Cartas/Cidade/24.jpg', 'Armadilha', NULL, NULL, 0, 0, 0, 0, 'Descarte um item da mochila.', TRUE, 3, 0, FALSE),
(18, 'Arame esticado', 'Cidade', 'Cartas/Cidade/25.jpg', 'Armadilha', NULL, NULL, 0, 0, 0, 0, 'Você não viu esse arame? perca um item de cabeça.', TRUE, 2, 0, FALSE),
(19, 'Lerdo', 'Cidade', 'Cartas/Cidade/26.jpg', 'Zumbie', NULL, NULL, 1, 1, 1, 0, 'Devagar mais te pega, se perder o combate perde o que estiver usando na cabeça e um item aleatório da mochila, se não tiver nada na cabeça perca 1 nível.', FALSE, 1, 0, FALSE),
(20, 'Rapido', 'Cidade', 'Cartas/Cidade/27.jpg', 'Zumbie', NULL, NULL, 5, 2, 1, 0, 'Corre, esse é rápido, necessário +2 para fuga, se perder descarte toda sua mão ou perde 2 níveis.', FALSE, 1, 0, FALSE),
(21, 'Lerdo', 'Cidade', 'Cartas/Cidade/28.jpg', 'Zumbie', NULL, NULL, 3, 1, 1, 0, 'se derrotar usando a carta fraco ganhe um item adicional, +2 contra personagem de força 2, se perder perde um item da mochila e um item da cartela, a sua escolha.', FALSE, 1, 0, FALSE),
(22, 'Mutação', 'Cidade', 'Cartas/Cidade/29.jpg', 'Zumbie', NULL, NULL, 18, 5, 2, 0, 'Não persegue jogadores que estão abaixo do nível 4, se perder perde tudo que tem na mochila e na mão.', FALSE, 1, 0, FALSE),
(23, 'Moondust', 'Cidade', 'Cartas/Cidade/3.png', 'Chacaras', '80', NULL, 0, 0, 1, 4, 'Já não tínhamos muito, e este vírus tirou o resto que sobrou, fuga >=4.', FALSE, 1, 0, FALSE),
(24, 'Gordo', 'Cidade', 'Cartas/Cidade/30.jpg', 'Zumbie', NULL, NULL, 10, 3, 1, 0, 'Uma dessa na cabeça e te deixa um pouco tonto, se perder perde o que esta na cabeça e 3 níveis.', FALSE, 1, 0, FALSE),
(25, 'Mestre', 'Cidade', 'Cartas/Cidade/31.jpg', 'Zumbie', NULL, NULL, 20, 5, 2, 0, 'Não persegue jogadores com nível inferior a 5, se perder para ele é melhor deixar tudo p traz, descarte toda sua mão e cartela, pode ficar com a mochila personagem e sua fazenda. ', FALSE, 1, 0, FALSE),
(26, 'Lerdo', 'Cidade', 'Cartas/Cidade/26.jpg', 'Zumbie', NULL, NULL, 1, 0, 0, 0, NULL, FALSE, 1, 0, FALSE),
