(28, 'Gordo', 'Cidade', 'Cartas/Cidade/34.jpg', 'Zumbie', NULL, NULL, 8, 2, 1, 0, 'Só pode combater este zumbi com o valor do nível, se perder perde sua fazenda e 3 níveis.', FALSE, 1, 0, FALSE),
(29, 'Gordo mutado', 'Cidade', 'Cartas/Cidade/35.jpg', 'Zumbie', NULL, NULL, 12, 3, 1, 0, '+3 de força contra jogadores que possuem força na sua carta, de perder perde o que estiver usando no pé e 1 nível.', FALSE, 2, 0, FALSE),
(30, 'Explosivo', 'Cidade', 'Cartas/Cidade/36.jpg', 'Zumbie', NULL, NULL, 16, 4, 2, 0, 'Não ataca jogadores que estão antes do nível 3, jogadores que estejam depois disso voltam 2 níveis, se perder ele explode e vc perde todas as cartas da carteira e da mão.', FALSE, 2, 0, FALSE),
(31, 'Gordo mutado', 'Cidade', 'Cartas/Cidade/37.jpg', 'Zumbie', NULL, NULL, 16, 4, 2, 0, 'Não ataca jogadores que estão antes do nível 3, jogadores que estejam depois disso voltam 2 níveis mesmo se escaparem, se perder ele te corta e vc volta para o nível 1.', FALSE, 1, 0, FALSE),
(32, 'Rastejante', 'Cidade', 'Cartas/Cidade/38.jpg', 'Zumbie', NULL, NULL, 1, 1, 1, 0, 'Rastejantes tem pouca velocidade, porem ao tropeçar em um pode ter grandes problemas.', FALSE, 5, 0, FALSE),
(34, 'Bela vista', 'Cidade', 'Cartas/Cidade/4.jpg', 'Chacaras', '80', NULL, 2, 0, 0, 0, 'Nesse lugar o barulho dentro da casa não atrai zumbi, pois a cachoeira abafa os sons, força +2.', FALSE, 1, 0, FALSE),
(35, 'Henry', 'Cidade', 'Cartas/Cidade/40.jpg', 'Sobrevivente', '79', '82', 1, 0, 0, 4, 'Jovem nem terminou o colegial e já esta sozinho cuidando de sua irmã mais nova, força +1, fuga >=4, não pode usar itens de corpo. ', FALSE, 1, 0, FALSE),
(36, 'Sheyla', 'Cidade', 'Cartas/Cidade/41.jpg', 'Sobrevivente', '79', '81', 1, 0, 0, 4, 'Após perder o marido, ficou sozinha cuidando de sua fazenda, força +1, Fuga >=4, não pode usar itens de cabeça.', FALSE, 1, 0, FALSE),
(37, 'Lucas', 'Cidade', 'Cartas/Cidade/42.jpg', 'Sobrevivente', '79', '82', 1, 0, 0, 0, 'Estudante que ao perder os pais nesse caos ficou para proteger a família, força +1', FALSE, 1, 0, FALSE),
(38, 'Leila', 'Cidade', 'Cartas/Cidade/43.jpg', 'Sobrevivente', '79', '82', 0, 0, 0, 4, 'Filha unica e com a morte dos pais ficou para cuidar dos avôs, fuga >= 4', FALSE, 1, 0, FALSE),
